+        for (int i = -halfWindow; i <= halfWindow; ++i) {
+            int accessIdx = threadIdx.x + i;
+            // Check bounds within shared memory
+            if (accessIdx >= 0 && accessIdx < blockDim.x && (idx + i) < n && (idx + i) >= 0) {
+                sum += sharedData[accessIdx];
+            }
+        }
+        output[idx] = sum;
